var e=[{id:`L2_1`,type:`dialog`,speaker:`CHOI_ALPHA_NULL_SHORT`,text:{KOREA:`동생이여, 조심해라!`,JPN:`妹よ、気を付けろ！`,ENG:`Little sister, be careful!`,TWN:`妹妹小心！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`CHOI_ALPHA_NULL_SHORT`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SPEAR_ALPHA_NULL_SHORT`,text:{KOREA:`칫……! 알고 있어!`,JPN:`ちっ……！　わかってるよ！`,ENG:`Tch...! I know!`,TWN:`嘖……！我知道啦！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`SPEAR_ALPHA_NULL_SHORT`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SPEAR_ALPHA_NULL_SHORT`,text:{KOREA:`으앙!? 아파!`,JPN:`うわぁ！　痛い！`,ENG:`Ouch! It stings!`,TWN:`哎呀！好痛喔！`},stage:{bg:`LABORATORY_03`,slots:{L:{char_id:`SPEAR_ALPHA_NULL_SHORT`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`CHOI_ALPHA_NULL_SHORT`,face:`UNIT_SURPRISE`}}}},{id:`L12_1`,type:`dialog`,speaker:`SPEAR_ALPHA_NULL_SHORT`,text:{KOREA:`……어라? 그런데 생각했던 것보다 덜 아프네?`,JPN:`……あれ？　でも思ったより痛くない！`,ENG:`Huh...? It doesn’t hurt as much as I had expected.`,TWN:`……奇怪？可是又好像沒想像中那麼痛？`},stage:{bg:`LABORATORY_03`,slots:{L:{char_id:`SPEAR_ALPHA_NULL_SHORT`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOI_ALPHA_NULL_SHORT`,face:`UNIT_SURPRISE`}}}},{id:`L13_1`,type:`dialog`,speaker:`CHOI_ALPHA_NULL_SHORT`,text:{KOREA:`음? 하지만 대장이 사용하는 특수탄의 위력은 동생이 버텨낼 정도가 아닌데?`,JPN:`うむ？　でも隊長が使う特殊弾の威力は妹が耐えられる程度のものでは
ないはずだが？`,ENG:`Hmm? But the special munition Cap uses should be powerful enough to knock you out.`,TWN:`嗯？如果是隊長使用的是特殊彈，那個威力你應該承受不住吧？`},stage:{bg:`LABORATORY_03`,slots:{L:{char_id:`SPEAR_ALPHA_NULL_SHORT`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHOI_ALPHA_NULL_SHORT`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`CHOWON_ALPHA_NULL_NULL`,text:{KOREA:`역시, 리더는 처음부터 이런 상황도 내다보고 있었군요.`,JPN:`やっぱり、リーダーは最初からこうなることを見込んでいたようですね。`,ENG:`Looks like Leader already knew this would happen from the start.`,TWN:`果然，老大應該從一開始就有預料到會是這種情況。`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`CHOWON_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHOWON_ALPHA_NULL_NULL`,text:{KOREA:`전원! 리더의 공격은 몸으로 받아내면서 육탄전으로 밀어붙여!`,JPN:`総員！　リーダーの攻撃を受け止めながら肉弾戦で押し上げよ！`,ENG:`Everybody! Block Leader's attack with your body and advance close enough for hand-to-hand combat!`,TWN:`全員注意！用身體來擋老大的攻擊，同時使用肉搏戰！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`CHOWON_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SEAROM_ALPHA_NULL_NULL`,text:{KOREA:`좋아! 뭔지 몰라도 육탄전이라면 환영이지!`,JPN:`よし！　なんだかわからないけど、肉弾戦なら歓迎だよ！`,ENG:`Okay! I don’t know what’s going on, but I welcome close combat any day of the week!`,TWN:`好欸！雖然聽不太懂，但我最喜歡肉搏戰！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`CHOWON_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`SEAROM_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L26_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`큭……!`,JPN:`くっ……！`,ENG:`Khhk...!`,TWN:`呃……！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`마, 말도 안 돼…….`,JPN:`し、信じられない……`,ENG:`I-impossible...`,TWN:`這…怎麼可能……`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_HATE`}}}},{id:`L28_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`내 최강의 기물이…… 여왕이 저런 버러지들에게 밀린다고?`,JPN:`私の最強の駒が……クイーンがあんな雑魚どもに押されている？`,ENG:`My most powerful piece... How can the queen lose to mere pawns?`,TWN:`我最強的棋子……皇后竟然被區區的小兵給逼到牆角？`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`웃기지 마……! 그럴 리가 없잖아!`,JPN:`ふざけるな……！　そんなわけないわ！`,ENG:`It can’t be...! There's no way!`,TWN:`想耍我……！我不相信！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`}}}},{id:`L30_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`일어나, 신지아!! 이제 장난은 때려치워!`,JPN:`起きなさい、ヒメノ・ユイ！！　冗談は終わりよ！`,ENG:`Get up, Shin Jia!! Stop fooling around!`,TWN:`沈佳，你給我起來！！現在不是開玩笑的時候！`},stage:{bg:`LABORATORY_03`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_SERIOUS2`}}}}];export{e as default};